import { getRequestHeaders } from "@tanstack/start-server-core";
import { setupFetchInterceptor } from "request-mocking-protocol/fetch";

const RMP_SETUP = Symbol.for("rmp-fetch-interceptor-setup");
const MOCK_HEADER = "x-mock-request";

export function setupRequestMocking() {
  if ((globalThis as Record<symbol, unknown>)[RMP_SETUP]) return;
  (globalThis as Record<symbol, unknown>)[RMP_SETUP] = true;

  const realFetch = globalThis.fetch;

  // Guard: when RMP can't match a request it falls through to "originalFetch".
  // We replace that fallback so unhandled *test* requests throw a clear error
  // instead of silently hitting the real network.
  globalThis.fetch = ((input: RequestInfo | URL, init?: RequestInit) => {
    const req = new Request(input, init);
    if (req.headers.has(MOCK_HEADER)) {
      throw new Error(
        `[RMP] No matching mock for: ${req.method} ${req.url}\n` +
          "All server-side requests must have a matching mock in tests.",
      );
    }
    return realFetch(input, init);
  }) as typeof fetch;

  // Shared variable: the outermost wrapper stores the outgoing request's headers
  // here so the RMP callback can read the mock header from them when the TanStack
  // request context is unavailable (e.g. client-to-server function calls).
  let outgoingHeaders: Headers | undefined;

  // RMP captures the current globalThis.fetch (our guard) as its fallback,
  // then replaces globalThis.fetch with its interceptor.
  setupFetchInterceptor(() => {
    try {
      const h = getRequestHeaders();
      if (h?.get(MOCK_HEADER)) return h;
    } catch {
      // TanStack request context not available
    }
    if (outgoingHeaders?.has(MOCK_HEADER)) return outgoingHeaders;
    return undefined;
  });

  // Outermost wrapper: captures outgoing headers before RMP processes the request.
  // This lets the callback above fall back to reading x-mock-request from the
  // outgoing fetch (forwarded by forwardRmpMockHeader in org-api.server.ts).
  const rmpFetch = globalThis.fetch;
  globalThis.fetch = ((input: RequestInfo | URL, init?: RequestInit) => {
    outgoingHeaders = new Headers(
      input instanceof Request ? input.headers : init?.headers,
    );
    if (input instanceof Request && init?.headers) {
      for (const [k, v] of new Headers(init.headers)) {
        outgoingHeaders.set(k, v);
      }
    }
    return rmpFetch(input, init);
  }) as typeof fetch;
}

